 26→
 27→type Props = CompositeScreenProps<
 28→  BottomTabScreenProps<MainTabParamList, 'Profile'>,
 29→  NativeStackScreenProps<RootStackParamList>
 30→>;
 31→
 32→export function ProfileScreen({navigation}: Props) {
 33→  const {user, signOut} = useAuth();
 34→  const {colors} = useTheme();
 35→
 36→  const userDataQuery = useQuery({
 37→    queryKey: ['profile', user?.id],
 38→    enabled: Boolean(user?.id),
 39→    queryFn: () => mobileApi.getUserData(user?.id ?? ''),
 40→  });
 41→
 42→  const profile = userDataQuery.data?.userData?.[0];
 43→  const bgColor = profile?.profile_layout?.backgroundColor ?? colors.accentAmber;
 44→
 45→  const onSignOut = async () => {
 46→    Alert.alert('Sign Out', 'Are you sure you want to sign out?', [
 47→      {text: 'Cancel', style: 'cancel'},
 48→      {
 49→        text: 'Sign Out',
 50→        style: 'destructive',
 51→        onPress: async () => {
 52→          try {
 53→            await signOut();
 54→          } catch (error) {
 55→            Alert.alert(
 56→              'Sign out failed',
 57→              error instanceof Error ? error.message : 'Unknown error',
 58→            );
 59→          }
 60→        },
 61→      },
 62→    ]);
 63→  };
 64→
 65→  if (userDataQuery.isLoading) {
 66→    return (
 67→      <SafeAreaView style={[styles.safe, {backgroundColor: colors.bgPrimary}]}>
 68→        <View style={styles.loadingContainer}>
 69→          <ActivityIndicator color={colors.loaderColor} size="large" />
 70→        </View>
 71→      </SafeAreaView>
 72→    );
 73→  }
 74→
 75→  return (
 76→    <SafeAreaView style={[styles.safe, {backgroundColor: colors.bgPrimary}]} edges={['top']}>
 77→      <ScrollView showsVerticalScrollIndicator={false}>
 78→        {/* Header background */}
 79→        <View style={[styles.headerBg, {backgroundColor: bgColor}]}>
 80→          <Pressable
 81→            style={styles.settingsBtn}
 82→            onPress={() => {
 83→              // Navigate to settings when available
 84→              onSignOut();
 85→            }}
 86→            hitSlop={12}>
 87→            <SettingsIcon size={22} color="rgba(255,255,255,0.8)" />
 88→          </Pressable>
 89→        </View>
 90→
 91→        {/* Profile content */}
 92→        <View style={styles.profileContent}>
 93→          {/* Avatar */}
 94→          <View style={styles.avatarContainer}>
 95→            <Avatar
 96→              uri={profile?.image_url}
 97→              name={profile?.name}
 98→              size={100}
 99→              badge={profile?.badge_type as any}
100→            />
101→          </View>
102→
103→          {/* Name & username */}
104→          <GlassCard style={styles.nameCard}>
105→            <Text style={[styles.name, {color: colors.textHeading}]}>
106→              {profile?.name || user?.email || 'User'}
107→            </Text>
108→            {profile?.username && (
109→              <Text style={[styles.username, {color: colors.textMuted}]}>
110→                @{profile.username}
111→              </Text>
112→            )}
113→            {profile?.badge_type && (
114→              <View
115→                style={[
116→                  styles.badgePill,
117→                  {
118→                    backgroundColor:
119→                      profile.badge_type === 'legend'
120→                        ? 'rgba(255,215,0,0.15)'
121→                        : 'rgba(155,89,255,0.15)',
122→                    borderColor:
123→                      profile.badge_type === 'legend'
124→                        ? colors.badgeLegendBorder
125→                        : colors.badgeOGBorder,
126→                  },
127→                ]}>
128→                <Text
129→                  style={[
130→                    styles.badgeText,
131→                    {
132→                      color:
133→                        profile.badge_type === 'legend'
134→                          ? colors.badgeLegendBorder
135→                          : colors.badgeOGBorder,
136→                    },
137→                  ]}>
138→                  {profile.badge_type.toUpperCase()}
139→                </Text>
140→              </View>
141→            )}
142→          </GlassCard>
143→
144→          {/* Bio */}
145→          {profile?.bio ? (
146→            <GlassCard style={styles.bioCard}>
147→              <Text style={[styles.bio, {color: colors.textSecondary}]}>
148→                {profile.bio}
149→              </Text>
150→            </GlassCard>
151→          ) : null}
152→
153→          {/* Stats row */}
154→          <View style={styles.statsRow}>
155→            <GlassCard style={styles.statCard}>
156→              <Text style={[styles.statNumber, {color: colors.textHeading}]}>
157→                {profile?.posts_count ?? 0}
158→              </Text>
159→              <Text style={[styles.statLabel, {color: colors.textMuted}]}>
160→                Posts
161→              </Text>
162→            </GlassCard>
163→            <GlassCard style={styles.statCard}>
164→              <Text style={[styles.statNumber, {color: colors.textHeading}]}>
165→                {profile?.followers_count ?? 0}
166→              </Text>
167→              <Text style={[styles.statLabel, {color: colors.textMuted}]}>
168→                Followers
169→              </Text>
170→            </GlassCard>
171→            <GlassCard style={styles.statCard}>
172→              <Text style={[styles.statNumber, {color: colors.textHeading}]}>
173→                {profile?.following_count ?? 0}
174→              </Text>
175→              <Text style={[styles.statLabel, {color: colors.textMuted}]}>
176→                Following
177→              </Text>
178→            </GlassCard>
179→          </View>
180→
181→          {/* Action buttons */}
182→          <View style={styles.actionRow}>
183→            <View style={styles.actionButton}>
184→              <PrimaryButton label="Edit Profile" onPress={() => {}} kind="secondary" />
185→            </View>
186→            <View style={styles.actionButton}>
187→              <PrimaryButton label="My Stories" onPress={() => navigation.navigate('StoryDashboard')} kind="secondary" />
188→            </View>
189→          </View>
190→
191→          {/* Sign out */}
192→          <View style={styles.signOutSection}>
193→            <PrimaryButton label="Sign Out" onPress={onSignOut} kind="danger" />
194→          </View>
195→        </View>
196→      </ScrollView>
197→    </SafeAreaView>
198→  );
199→}
