290→  async saveJournal(token: string, payload: { title: string; plainText: string; html?: string }): Promise<{ message?: string }> {
291→    const formData = new FormData();
292→
293→    const lexicalPayload = {
294→      root: {
295→        children: [
296→          {
297→            type: 'paragraph',
298→            children: [
299→              {
300→                type: 'text',
301→                text: payload.plainText,
302→                detail: 0,
303→                format: 0,
304→                mode: 'normal',
305→                style: '',
306→                version: 1,
307→              },
308→            ],
309→            direction: null,
310→            format: '',
311→            indent: 0,
312→            version: 1,
313→          },
314→        ],
315→        direction: null,
316→        format: '',
317→        indent: 0,
318→        type: 'root',
319→        version: 1,
320→      },
321→    };
322→
323→    formData.append('title', payload.title);
324→    formData.append('content', JSON.stringify(lexicalPayload));
325→    formData.append('post_type', 'text');
326→
327→    return apiRequest<{ message?: string }>('/save-journal', {
328→      method: 'POST',
329→      headers: {
330→        ...authHeaders(token),
331→      },
332→      body: formData,
333→      timeoutMs: 30000,
334→      retries: 0,
335→    });
336→  },
