 16→function getInitials(name?: string): string {
 17→  if (!name) return '?';
 18→  const parts = name.trim().split(/\s+/);
 19→  if (parts.length === 1) return parts[0][0]?.toUpperCase() ?? '?';
 20→  return (parts[0][0] + parts[parts.length - 1][0]).toUpperCase();
 21→}
 22→
 23→export function Avatar({uri, name, size = 40, badge}: AvatarProps) {
 24→  const {colors} = useTheme();
 25→
 26→  const ringSize = size + 6;
 27→  const hasRing = badge === 'legend' || badge === 'og';
 28→  const ringColor =
 29→    badge === 'legend'
 30→      ? colors.badgeLegendBorder
 31→      : badge === 'og'
 32→        ? colors.badgeOGBorder
 33→        : 'transparent';
 34→
 35→  const content = uri ? (
 36→    <Image
 37→      source={{uri}}
 38→      style={[
 39→        styles.image,
 40→        {width: size, height: size, borderRadius: size / 2},
 41→      ]}
 42→    />
 43→  ) : (
 44→    <View
 45→      style={[
 46→        styles.placeholder,
 47→        {
 48→          width: size,
 49→          height: size,
 50→          borderRadius: size / 2,
 51→          backgroundColor: colors.bgSecondary,
 52→        },
 53→      ]}>
 54→      <Text
 55→        style={[
 56→          styles.initials,
 57→          {color: colors.textMuted, fontSize: size * 0.38},
 58→        ]}>
 59→        {getInitials(name)}
 60→      </Text>
 61→    </View>
 62→  );
 63→
 64→  if (hasRing) {
 65→    return (
 66→      <View
 67→        style={[
 68→          styles.ring,
 69→          {
 70→            width: ringSize,
 71→            height: ringSize,
 72→            borderRadius: ringSize / 2,
 73→            borderColor: ringColor,
 74→          },
 75→        ]}>
 76→        {content}
 77→      </View>
 78→    );
 79→  }
 80→
 81→  return content;
 82→}
