 38→                path: targetMedia.path,
 39→                url: targetMedia.url,
 40→            }),
 41→        onSuccess: (response, targetMedia) => {
 42→            setDeleteCandidate(null);
 43→            setActiveMenuId(null);
 44→
 45→            if (selectedMedia?.id === targetMedia?.id) {
 46→                setSelectedMedia(null);
 47→            }
 48→
 49→            queryClient.setQueryData(["profileMedia", userId], (oldData) => {
 50→                if (!oldData || !Array.isArray(oldData.pages)) {
 51→                    return oldData;
 52→                }
 53→
 54→                return {
 55→                    ...oldData,
 56→                    pages: oldData.pages.map((page) => ({
 57→                        ...page,
 58→                        data: Array.isArray(page?.data) ? page.data.filter((item) => item.id !== targetMedia.id) : page?.data,
 59→                    })),
 60→                };
 61→            });
 62→
 63→            queryClient.invalidateQueries({ queryKey: ["profileMedia", userId] });
 64→
 65→            if (response?.clearedAvatar || response?.clearedBackground) {
 66→                queryClient.invalidateQueries({ queryKey: ["userData"] });
 67→            }
 68→        },
 69→    });
 70→
 71→    const handleOpenMedia = (item) => {
 72→        if (!item?.url) return;
 73→        setSelectedMedia(item);
 74→    };
 75→
 76→    const handleToggleSettingsMenu = (event, mediaId) => {
 77→        event.stopPropagation();
 78→        setActiveMenuId((currentId) => (currentId === mediaId ? null : mediaId));
 79→    };
 80→
 81→    const handleOpenDeleteModal = (event, item) => {
 82→        event.stopPropagation();
 83→        setDeleteCandidate(item);
 84→        setActiveMenuId(null);
 85→    };
 86→
 87→    const handleCloseDeleteModal = () => {
 88→        setDeleteCandidate(null);
 89→    };
 90→
 91→    const handleConfirmDelete = () => {
 92→        if (!deleteCandidate || deleteMediaMutation.isPending) {
 93→            return;
 94→        }
 95→
 96→        deleteMediaMutation.mutate(deleteCandidate);
 97→    };
 98→
 99→    const handleCloseMedia = () => {
100→        setSelectedMedia(null);
101→    };
102→
103→    const profileParentContainer = typeof document !== "undefined" ? document.querySelector(".profile-parent-container") : null;
104→
105→    useEffect(() => {
106→        if (inView && hasNextPage && !isFetchingNextPage) {
107→            fetchNextPage();
108→        }
109→    }, [inView, hasNextPage, isFetchingNextPage, fetchNextPage]);
110→
111→    useEffect(() => {
112→        const handleWindowClick = (event) => {
113→            if (!event.target.closest(".profile-media-item-actions")) {
114→                setActiveMenuId(null);
115→            }
116→        };
117→
118→        window.addEventListener("click", handleWindowClick);
119→        return () => window.removeEventListener("click", handleWindowClick);
120→    }, []);
121→
122→    useEffect(() => {
123→        if (!selectedMedia && !deleteCandidate) return;
124→
125→        const handleEscape = (event) => {
126→            if (event.key === "Escape") {
127→                if (deleteCandidate) {
128→                    handleCloseDeleteModal();
129→                    return;
130→                }
131→
132→                handleCloseMedia();
133→            }
134→        };
135→
136→        window.addEventListener("keydown", handleEscape);
137→        return () => window.removeEventListener("keydown", handleEscape);
138→    }, [selectedMedia, deleteCandidate]);
139→
140→    return (
141→        <section className="profile-media-section" aria-label="Profile media">
142→            <div className="profile-media-header-row">
143→                <h2 className="profile-media-heading">
144→                    Posts <span className="profile-media-count">({mediaItems.length})</span>
145→                </h2>
146→            </div>
147→
148→            {unavailableBuckets.length > 0 && <p className="profile-media-warning">Unable to list: {unavailableBuckets.join(", ")}.</p>}
149→
150→            {isLoading && (
151→                <div className="profile-media-grid">
152→                    {Array.from({ length: 9 }).map((_, index) => (
153→                        <div key={`media-loading-${index}`} className="profile-media-grid-item profile-media-grid-loading-item" />
154→                    ))}
155→                </div>
156→            )}
157→
158→            {!isLoading && isError && <p className="profile-media-empty-state">Unable to load your media right now.</p>}
159→
160→            {!isLoading && !isError && !hasMedia && <p className="profile-media-empty-state">No media found in your buckets yet.</p>}
161→
162→            {!isLoading && !isError && hasMedia && (
163→                <div className="profile-media-grid">
164→                    {mediaItems.map((item) => (
165→                        <div key={item.id} className="profile-media-grid-item">
166→                            <button
