192→                            </div>
193→                        </div>
194→                    ))}
195→                    {isFetchingNextPage &&
196→                        Array.from({ length: PROFILE_MEDIA_PAGE_SIZE }).map((_, index) => (
197→                            <div key={`media-loading-next-${index}`} className="profile-media-grid-item profile-media-grid-loading-item" />
198→                        ))}
199→                </div>
200→            )}
201→
202→            {!isLoading && hasMedia && hasNextPage && <div ref={inViewRef} className="profile-media-infinite-sentinel" />}
203→
204→            {selectedMedia &&
205→                profileParentContainer &&
206→                createPortal(
