218→
219→            {deleteCandidate &&
220→                profileParentContainer &&
221→                createPortal(
222→                <div className="profile-media-delete-confirm-overlay" onClick={handleCloseDeleteModal} role="presentation">
223→                    <div className="profile-media-delete-confirm-dialog" role="dialog" aria-modal="true" aria-label="Delete media image" onClick={(event) => event.stopPropagation()}>
