1298→    const RESERVED_WORDS = ['admin', 'root', 'iskrib', 'iskryb', 'support', 'help', 'api', 'www', 'null', 'undefined'];
1299→    if (RESERVED_WORDS.includes(normalized)) {
1300→        return res.status(400).json({ error: 'this username is reserved' });
1301→    }
1302→
1303→    // Check uniqueness
1304→    const { data: existing } = await supabase
1305→        .from('users')
1306→        .select('id')
1307→        .ilike('username', normalized)
1308→        .neq('id', userId)
1309→        .limit(1);
1310→
1311→    if (existing && existing.length > 0) {
