355→export const getMyStoriesService = async (userId, limit, before) => {
356→    if (!userId) {
357→        throw { status: 400, error: 'userId is required' };
358→    }
359→
360→    const parsedLimit = Math.min(Math.max(parseInt(limit) || 5, 1), 20);
361→
362→    let query = supabase
363→        .from('stories')
364→        .select(`${STORY_SELECT_COLUMNS}, chapters(id, chapter_number, title, status, word_count)`)
365→        .eq('author_id', userId)
366→        .order('updated_at', { ascending: false })
367→        .limit(parsedLimit + 1);
