export type AuthStackParamList = {
  Login: undefined;
  SignUp: undefined;
  ForgotPassword: undefined;
};

export type MainTabParamList = {
  Home: undefined;
  Explore: undefined;
  Stories: undefined;
  Notifications: undefined;
  Profile: undefined;
};

export type RootStackParamList = {
  Auth: undefined;
  Main: undefined;
  PostDetail: {journalId: string; slug?: string};
  JournalEditor: {mode: 'create' | 'edit'; journalId?: string};
  StoryDetail: {storyId: string};
  StoryEditor: {storyId?: string};
  StoryDashboard: undefined;
  StoryLibrary: undefined;
  StoryChapterManager: {storyId: string};
  StoryChapterEditor: {storyId: string; chapterId: string};
  StoryChapterReader: {storyId: string; chapterId: string};
  Canvas: undefined;
  FreedomWall: undefined;
  Universe: undefined;
  VisitProfile: {userId: string; username?: string};
  EditProfile: undefined;
  Settings: undefined;
  FollowList: {userId: string; tab: 'followers' | 'following'};
  Collections: undefined;
  CollectionDetail: {collectionId: string; name: string};
};

import {Platform, ViewStyle} from 'react-native';
import type {Palette} from './tokens';

export const spacing = {
  xxs: 2,
  xs: 4,
  sm: 8,
  md: 12,
  lg: 16,
  xl: 20,
  xxl: 24,
  xxxl: 32,
  xxxxl: 40,
} as const;

export const radii = {
  xs: 4,
  sm: 6,
  md: 8,
  lg: 10,
  xl: 12,
  xxl: 14,
  xxxl: 16,
  hero: 20,
  pill: 999,
} as const;

// Shadow factory — returns platform-appropriate shadow styles
export function shadows(colors: Palette) {
  return {
    card: Platform.select({
      ios: {
        shadowColor: colors.bgPrimary === '#FAF9F6' ? 'rgba(80,60,40,0.08)' : 'rgba(0,0,0,0.4)',
        shadowOffset: {width: 0, height: 2},
        shadowOpacity: 1,
        shadowRadius: 8,
      },
      android: {
        elevation: 2,
      },
    }) as ViewStyle,

    cardSm: Platform.select({
      ios: {
        shadowColor: colors.bgPrimary === '#FAF9F6' ? 'rgba(80,60,40,0.06)' : 'rgba(0,0,0,0.3)',
        shadowOffset: {width: 0, height: 1},
        shadowOpacity: 1,
        shadowRadius: 3,
      },
      android: {
        elevation: 1,
      },
    }) as ViewStyle,

    elevated: Platform.select({
      ios: {
