 38→const PAGE_SIZE = 10;
 39→
 40→const extractPlainText = (rawContent: string | null | undefined): string => {
 41→  if (!rawContent) return '';
 42→  try {
 43→    const parsed = JSON.parse(rawContent) as {
 44→      root?: {children?: Array<{children?: Array<{text?: string}>}>};
 45→    };
 46→    const parts: string[] = [];
 47→    parsed.root?.children?.forEach(node => {
 48→      node.children?.forEach(child => {
 49→        if (child.text) parts.push(child.text);
 50→      });
 51→    });
 52→    return parts.join(' ').replace(/\s+/g, ' ').trim();
 53→  } catch {
 54→    return rawContent.replace(/\s+/g, ' ').trim();
 55→  }
 56→};
 57→
 58→const extractBannerImage = (
 59→  rawContent: string | null | undefined,
 60→  images?: string | string[] | null,
 61→): string | null => {
 62→  // Check images field first
 63→  if (images) {
 64→    if (typeof images === 'string') {
 65→      try {
 66→        const parsed = JSON.parse(images);
 67→        if (Array.isArray(parsed) && parsed.length > 0) return parsed[0];
 68→      } catch {
 69→        if (images.startsWith('http')) return images;
 70→      }
 71→    }
 72→    if (Array.isArray(images) && images.length > 0) return images[0];
 73→  }
 74→  // Try to find image node in Lexical content
 75→  if (!rawContent) return null;
 76→  try {
 77→    const parsed = JSON.parse(rawContent);
 78→    const findImage = (node: any): string | null => {
 79→      if (node.type === 'image' && node.src) return node.src;
 80→      if (node.children) {
 81→        for (const child of node.children) {
 82→          const found = findImage(child);
 83→          if (found) return found;
 84→        }
 85→      }
 86→      return null;
 87→    };
 88→    return findImage(parsed.root ?? parsed);
 89→  } catch {
 90→    return null;
 91→  }
 92→};
 93→
 94→const getNextCursor = (page: CursorPage<JournalItem>): string | undefined => {
 95→  if (page.nextCursor) return page.nextCursor;
 96→  if (page.hasMore && page.data.length > 0)
 97→    return page.data[page.data.length - 1]?.created_at ?? undefined;
 98→  if (page.data.length >= PAGE_SIZE)
 99→    return page.data[page.data.length - 1]?.created_at ?? undefined;
100→  return undefined;
101→};
102→
103→const normalizeCount = (value: unknown): number => {
104→  const parsed = Number(value);
105→  return Number.isFinite(parsed) && parsed >= 0 ? parsed : 0;
106→};
107→
108→const resolveCount = (
109→  aggregate: Array<{count?: number}> | undefined,
110→  fallback?: number,
111→): number => {
112→  if (Array.isArray(aggregate) && aggregate.length > 0)
113→    return normalizeCount(aggregate[0]?.count);
114→  return normalizeCount(fallback);
115→};
