 22→const getNext = (page: {data: StoryItem[]; hasMore?: boolean}) => {
 23→  if (!page.hasMore || page.data.length === 0) {
 24→    return undefined;
 25→  }
 26→  return page.data[page.data.length - 1]?.updated_at;
 27→};
