  1→import {apiRequest} from './apiClient';
  2→
  3→export type StoryStatus = 'ongoing' | 'completed' | 'hiatus' | string;
  4→export type StoryPrivacy = 'public' | 'private' | string;
  5→
  6→export type StoryItem = {
  7→  id: string;
  8→  title: string;
  9→  description?: string | null;
 10→  status?: StoryStatus;
 11→  privacy?: StoryPrivacy;
 12→  tags?: string[];
 13→  cover_url?: string | null;
 14→  vote_count?: number;
 15→  read_count?: number;
 16→  has_voted?: boolean;
 17→  in_library?: boolean;
 18→  created_at?: string;
 19→  updated_at?: string;
 20→  users?: {
 21→    id?: string;
 22→    name?: string;
 23→    username?: string;
 24→    image_url?: string;
 25→  } | null;
 26→  chapters?: StoryChapterSummary[];
 27→  reading_progress?: {
 28→    chapter_id?: string;
 29→    scroll_position?: number;
 30→  } | null;
 31→};
 32→
 33→export type StoryChapterSummary = {
 34→  id: string;
 35→  title: string;
 36→  chapter_number?: number;
 37→  status?: 'draft' | 'published' | string;
 38→  word_count?: number;
 39→};
 40→
 41→export type StoryChapter = StoryChapterSummary & {
 42→  content?: string | object | null;
 43→  prev_chapter?: StoryChapterSummary | null;
 44→  next_chapter?: StoryChapterSummary | null;
 45→};
 46→
 47→export type StoryListResponse = {
 48→  data: StoryItem[];
 49→  hasMore?: boolean;
 50→};
 51→
 52→const authHeaders = (token?: string): Record<string, string> => {
 53→  if (!token) {
 54→    return {};
 55→  }
 56→  return {Authorization: `Bearer ${token}`};
 57→};
 58→
 59→const appendBeforeLimit = (
 60→  params: URLSearchParams,
 61→  limit: number,
 62→  before?: string | null,
 63→) => {
 64→  params.set('limit', String(limit));
 65→  if (before) {
 66→    params.set('before', before);
 67→  }
 68→};
 69→
 70→export const storyApi = {
 71→  async getStories(
 72→    options: {
 73→      limit?: number;
 74→      before?: string | null;
 75→      status?: StoryStatus | null;
 76→      tag?: string | null;
 77→      token?: string;
 78→    } = {},
 79→  ): Promise<StoryListResponse> {
 80→    const params = new URLSearchParams();
 81→    appendBeforeLimit(params, options.limit ?? 10, options.before);
 82→    if (options.status) {
 83→      params.set('status', options.status);
 84→    }
 85→    if (options.tag) {
 86→      params.set('tag', options.tag);
 87→    }
 88→
 89→    return apiRequest<StoryListResponse>(`/stories?${params.toString()}`, {
 90→      method: 'GET',
 91→      headers: {
 92→        ...authHeaders(options.token),
 93→      },
 94→    });
 95→  },
 96→
 97→  async getStoryById(storyId: string, token?: string): Promise<StoryItem> {
 98→    return apiRequest<StoryItem>(`/stories/${encodeURIComponent(storyId)}`, {
 99→      method: 'GET',
100→      headers: {
101→        ...authHeaders(token),
102→      },
103→    });
104→  },
105→
106→  async getMyStories(
107→    token: string,
108→    options: {limit?: number; before?: string | null} = {},
109→  ): Promise<StoryListResponse> {
110→    const params = new URLSearchParams();
111→    appendBeforeLimit(params, options.limit ?? 10, options.before);
112→    return apiRequest<StoryListResponse>(`/stories/my?${params.toString()}`, {
113→      method: 'GET',
114→      headers: {
115→        ...authHeaders(token),
116→      },
117→    });
118→  },
119→
120→  async getMyLibrary(
121→    token: string,
122→    options: {limit?: number; before?: string | null} = {},
123→  ): Promise<StoryListResponse> {
124→    const params = new URLSearchParams();
125→    appendBeforeLimit(params, options.limit ?? 10, options.before);
126→    return apiRequest<StoryListResponse>(`/stories/library?${params.toString()}`, {
127→      method: 'GET',
128→      headers: {
129→        ...authHeaders(token),
130→      },
131→    });
132→  },
133→
134→  async getUserStories(
135→    userId: string,
136→    token?: string,
137→    options: {limit?: number; before?: string | null} = {},
138→  ): Promise<StoryListResponse> {
139→    const params = new URLSearchParams();
140→    appendBeforeLimit(params, options.limit ?? 10, options.before);
141→    return apiRequest<StoryListResponse>(
142→      `/stories/user/${encodeURIComponent(userId)}?${params.toString()}`,
143→      {
144→        method: 'GET',
145→        headers: {
146→          ...authHeaders(token),
147→        },
148→      },
149→    );
150→  },
151→
152→  async createStory(
153→    token: string,
154→    payload: {
155→      title: string;
156→      description?: string;
157→      status?: StoryStatus;
158→      privacy?: StoryPrivacy;
159→      tags?: string[];
160→      coverImageUri?: string | null;
161→      coverMimeType?: string;
162→      coverFileName?: string;
163→    },
164→  ): Promise<StoryItem> {
165→    const formData = new FormData();
166→    formData.append('title', payload.title.trim());
167→    formData.append('description', payload.description?.trim() ?? '');
168→    formData.append('status', payload.status ?? 'ongoing');
169→    formData.append('privacy', payload.privacy ?? 'public');
170→    formData.append('tags', JSON.stringify(payload.tags ?? []));
171→
172→    if (payload.coverImageUri) {
173→      formData.append('image', {
174→        uri: payload.coverImageUri,
175→        type: payload.coverMimeType ?? 'image/jpeg',
176→        name: payload.coverFileName ?? 'story-cover.jpg',
177→      } as never);
178→    }
179→
180→    return apiRequest<StoryItem>('/stories', {
181→      method: 'POST',
182→      headers: {
183→        ...authHeaders(token),
184→      },
185→      body: formData,
186→    });
187→  },
188→
189→  async updateStory(
190→    token: string,
191→    storyId: string,
192→    payload: {
