 5→
 6→type ScreenProps = {
 7→  children: React.ReactNode;
 8→  scroll?: boolean;
 9→  contentContainerStyle?: StyleProp<ViewStyle>;
10→  padded?: boolean;
11→};
12→
13→export function Screen({children, scroll = true, contentContainerStyle, padded = true}: ScreenProps) {
14→  const {colors} = useTheme();
15→
16→  const content = scroll ? (
17→    <ScrollView
18→      contentContainerStyle={[
19→        padded && styles.content,
20→        contentContainerStyle,
21→      ]}
22→      showsVerticalScrollIndicator={false}>
23→      {children}
24→    </ScrollView>
25→  ) : (
26→    <View style={[padded && styles.content, contentContainerStyle, styles.flex]}>
27→      {children}
28→    </View>
29→  );
30→
31→  return (
32→    <SafeAreaView style={[styles.safeArea, {backgroundColor: colors.bgPrimary}]}>
33→      {content}
34→    </SafeAreaView>
35→  );
36→}
